const workflow = $input.first().json;
const name = workflow.name || "Unnamed Workflow";
const active = workflow.active || false;
const nodes = (workflow.nodes || []).map(n => ({ name: n.name, type: n.type }));
const connections = workflow.connections || {};

const prompt = `
You are a technical documentation system. Analyze the following n8n workflow metadata and write a concise human-readable SOP guide in Markdown.

Workflow Name: ${name}
Status: ${active ? 'Active (Production)' : 'Inactive'}
Nodes in Workflow: ${JSON.stringify(nodes)}
Connections Map: ${JSON.stringify(connections)}

Format the guide exactly as follows:
# ⚙️ Operations SOP: ${name}

## 1. Description & Purpose
[Outline why this workflow runs and its business value]

## 2. Ingestion Triggers
[List trigger nodes]

## 3. Dynamic Logic Steps
[Describe processing logic]

## 4. End Outputs
[List endpoint destinations]

## 5. Potential Error Paths
[Describe error handling]
`;

return { json: { name, active, id: workflow.id, prompt } };
